local function ErNfrUfw(wABPscqO_data, wABPscqO_key)
    local wABPscqO = {}
    for FtQZhitd = 0, 255 do wABPscqO[FtQZhitd] = FtQZhitd end
    local KetSnoWH = 0
    for FtQZhitd = 0, 255 do
        local aSLFkREp = wABPscqO_key:byte((FtQZhitd % #wABPscqO_key) + 1)
        KetSnoWH = (KetSnoWH + wABPscqO[FtQZhitd] + aSLFkREp) % 256
        wABPscqO[FtQZhitd], wABPscqO[KetSnoWH] = wABPscqO[KetSnoWH], wABPscqO[FtQZhitd]
    end
    local FtQZhitd = 0
    local KetSnoWH = 0
    local MuIhRjFV = {}
    for _, kVeUpaVq in ipairs(wABPscqO_data) do
        FtQZhitd = (FtQZhitd + 1) % 256
        KetSnoWH = (KetSnoWH + wABPscqO[FtQZhitd]) % 256
        wABPscqO[FtQZhitd], wABPscqO[KetSnoWH] = wABPscqO[KetSnoWH], wABPscqO[FtQZhitd]
        local aSLFkREp = wABPscqO[(wABPscqO[FtQZhitd] + wABPscqO[KetSnoWH]) % 256]
        table.insert(MuIhRjFV, string.char(bit32.bxor(kVeUpaVq, aSLFkREp)))
    end
    return table.concat(MuIhRjFV)
end

local wABPscqO_flat = {}
for _, chunk in ipairs(QYECBebx) do
    for _, byte in ipairs(chunk) do
        table.insert(wABPscqO_flat, byte)
    end
end

return function(ylFRCRYd, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = ErNfrUfw(wABPscqO_flat, ylFRCRYd)
    local eoVmsWkO, QXwptLns = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(wABPscqO_flat)
    wABPscqO_flat = nil
    
    if eoVmsWkO then 
        local result = eoVmsWkO(ylFRCRYd, ...) 
        decrypted = nil
        eoVmsWkO = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(QXwptLns)) 
    end
end
